const { ethers } = require('ethers');

async function createWallet(privateKey) {
  const wallet = new ethers.Wallet(privateKey);
  console.log(`Wallet Address: ${wallet.address}`);
  return wallet;
}

async function sendTransaction(wallet, toAddress, amountInEther) {
  const provider = ethers.getDefaultProvider('mainnet');
  const walletWithProvider = wallet.connect(provider);

  const tx = {
    to: toAddress,
    value: ethers.utils.parseEther(amountInEther),
  };

  const transactionResponse = await walletWithProvider.sendTransaction(tx);
  console.log(`Transaction Hash: ${transactionResponse.hash}`);

  const receipt = await transactionResponse.wait();
  console.log(`Transaction was mined in block: ${receipt.blockNumber}`);
}

async function interactWithContract(wallet, contractAddress, abi, functionName, ...args) {
  const provider = ethers.getDefaultProvider('mainnet');
  const walletWithProvider = wallet.connect(provider);
  const contract = new ethers.Contract(contractAddress, abi, walletWithProvider);

  const transactionResponse = await contract[functionName](...args);
  console.log(`Transaction Hash: ${transactionResponse.hash}`);

  const receipt = await transactionResponse.wait();
  console.log(`Transaction was mined in block: ${receipt.blockNumber}`);
}

